import{_ as t,o as a,c as o,ag as l}from"./chunks/framework.BYYsWsaA.js";const u=JSON.parse('{"title":"Build a Deck","description":"","frontmatter":{},"headers":[],"relativePath":"slides/build-a-deck.md","filePath":"slides/build-a-deck.md"}'),i={name:"slides/build-a-deck.md"};function r(d,e,n,s,h,c){return a(),o("div",null,[...e[0]||(e[0]=[l('<h1 id="build-a-deck" tabindex="-1">Build a Deck <a class="header-anchor" href="#build-a-deck" aria-label="Permalink to &quot;Build a Deck&quot;">​</a></h1><p>In this guide, you&#39;ll build a short three-slide deck from scratch. Along the way, you&#39;ll pick a theme, use a layout, add text and a shape, and present the deck full-screen.</p><h2 id="_1-create-a-new-presentation" tabindex="-1">1. Create a New Presentation <a class="header-anchor" href="#_1-create-a-new-presentation" aria-label="Permalink to &quot;1. Create a New Presentation&quot;">​</a></h2><p>From your workspace, click <strong>New</strong> → <strong>Presentation</strong>. You&#39;ll see a blank deck with a single title slide and a thumbnail strip on the left.</p><h2 id="_2-pick-a-theme" tabindex="-1">2. Pick a Theme <a class="header-anchor" href="#_2-pick-a-theme" aria-label="Permalink to &quot;2. Pick a Theme&quot;">​</a></h2><p>A <strong>theme</strong> controls the colors, fonts, and background used across every slide. Wafflebase ships with several built-in themes.</p><p>Open the <strong>Theme</strong> panel from the right sidebar and click any theme to apply it to the whole deck. You can switch themes any time — your content stays put.</p><p>See <a href="./themes-and-layouts.html">Themes &amp; Layouts</a> for the full set of built-in themes and how the four-tier theme model works.</p><h2 id="_3-add-a-title" tabindex="-1">3. Add a Title <a class="header-anchor" href="#_3-add-a-title" aria-label="Permalink to &quot;3. Add a Title&quot;">​</a></h2><p>The blank deck opens with a <strong>Title slide</strong> layout. Double-click the title placeholder and type a deck title — for example, <code>Q2 Roadmap</code>. Double-click the subtitle placeholder and add a short tagline.</p><p>The placeholders inherit the heading and body fonts from the active theme, so you don&#39;t need to format text manually.</p><h2 id="_4-add-a-content-slide" tabindex="-1">4. Add a Content Slide <a class="header-anchor" href="#_4-add-a-content-slide" aria-label="Permalink to &quot;4. Add a Content Slide&quot;">​</a></h2><p>Insert a new slide:</p><ul><li>Press <code>⌘+M</code> (Mac) or <code>Ctrl+M</code> (Windows/Linux), <strong>or</strong></li><li>Click the <strong>+</strong> button at the top of the slide thumbnail strip.</li></ul><p>The new slide reuses the current slide&#39;s layout. To pick a different layout, click the <strong>Layout</strong> split-button in the toolbar and choose <strong>Title and body</strong>.</p><p>Type a title — <code>Themes</code> — and add a few bullet points in the body placeholder:</p><ul><li>Theme picker in the right sidebar</li><li>One-click reskin of the whole deck</li><li>Built-in light and dark themes</li></ul><h2 id="_5-add-a-shape" tabindex="-1">5. Add a Shape <a class="header-anchor" href="#_5-add-a-shape" aria-label="Permalink to &quot;5. Add a Shape&quot;">​</a></h2><p>Slides ship with an OOXML-aligned shape library. From the toolbar, click <strong>Shape</strong> and pick a rectangle. Drag on the canvas to draw it.</p><p>With the shape selected, the <strong>Fill</strong> color in the toolbar shows the active theme palette at the top — so you can apply the theme&#39;s accent color without picking a hex value.</p><h2 id="_6-present" tabindex="-1">6. Present <a class="header-anchor" href="#_6-present" aria-label="Permalink to &quot;6. Present&quot;">​</a></h2><p>When you&#39;re ready to present:</p><ul><li>Press <code>⌘+Enter</code> / <code>Ctrl+Enter</code> to start from the current slide, <strong>or</strong></li><li>Press <code>⌘+Shift+Enter</code> / <code>Ctrl+Shift+Enter</code> to start from the first slide.</li></ul><p>In presentation mode:</p><ul><li><code>→</code> / <code>Page Down</code> / click — advance to the next slide</li><li><code>←</code> / <code>Page Up</code> — go back</li><li><code>Esc</code> — exit</li></ul><h2 id="what-s-next" tabindex="-1">What&#39;s Next <a class="header-anchor" href="#what-s-next" aria-label="Permalink to &quot;What&#39;s Next&quot;">​</a></h2><ul><li><a href="./themes-and-layouts.html">Themes &amp; Layouts</a> — Catalog of themes, layouts, and placeholders</li><li><a href="./keyboard-shortcuts.html">Keyboard Shortcuts</a> — Full shortcut reference</li><li><a href="/docs/guide/collaboration.html">Collaboration &amp; Sharing</a> — Invite others to co-edit the deck</li></ul>',27)])])}const m=t(i,[["render",r]]);export{u as __pageData,m as default};
